import{_ as e,o as i,c as t,ag as a}from"./chunks/framework.NIzFHKo_.js";const g=JSON.parse('{"title":"Obsidian & QiDocs Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/40_service_apps/30_capture/obsidian_qidocs.md","filePath":"10_core/40_service_apps/30_capture/obsidian_qidocs.md"}'),n={name:"10_core/40_service_apps/30_capture/obsidian_qidocs.md"};function r(s,o,d,l,c,u){return i(),t("div",null,[...o[0]||(o[0]=[a('<h1 id="obsidian-qidocs-configuration" tabindex="-1">Obsidian &amp; QiDocs Configuration <a class="header-anchor" href="#obsidian-qidocs-configuration" aria-label="Permalink to &quot;Obsidian &amp; QiDocs Configuration&quot;">​</a></h1><p>This document outlines the doctrine and configuration rules for using Obsidian as the primary local Markdown editing and navigation tool for QiDocs.</p><h2 id="vault-root" tabindex="-1">Vault Root <a class="header-anchor" href="#vault-root" aria-label="Permalink to &quot;Vault Root&quot;">​</a></h2><ul><li><strong>The Vault Root</strong>: The root of the Obsidian vault is the <code>/docs</code> directory.</li><li><strong>No Nested Vaults</strong>: Do not use or initialize nested <code>.obsidian</code> folders under <code>/docs/10_blueprint</code> or any other subdirectories. The vault boundary exists exclusively at the <code>/docs</code> level.</li></ul><h2 id="configuration-folder" tabindex="-1">Configuration Folder <a class="header-anchor" href="#configuration-folder" aria-label="Permalink to &quot;Configuration Folder&quot;">​</a></h2><ul><li><strong>Intended Config</strong>: The intended Obsidian configuration folder is <code>.obsidian-qidocs</code>.</li><li><strong>Version Control</strong>: Stable configuration (such as core settings, themes, and stable plugin lists) may be versioned in Git.</li><li><strong>Gitignored Churn</strong>: Highly volatile files that create commit churn—such as <code>workspace.json</code>, <code>workspace-mobile.json</code>, cache directories, and plugin state data—must be strictly <code>.gitignore</code>d.</li></ul><h2 id="role-in-the-system" tabindex="-1">Role in the System <a class="header-anchor" href="#role-in-the-system" aria-label="Permalink to &quot;Role in the System&quot;">​</a></h2><ul><li><strong>Obsidian</strong>: Used strictly for local editing, writing, and Markdown file navigation.</li><li><strong>Wiki.js</strong>: Acts as the readable, accessible knowledge base for the system.</li><li><strong>Source of Truth</strong>: Raw Markdown and YAML files remain the definitive source of truth at all times.</li><li><strong>MarkMind / Visuals</strong>: MarkMind (and similar tools) provide a generated visual layer for convenience. They are <em>not</em> the source of truth.</li></ul>',8)])])}const f=e(n,[["render",r]]);export{g as __pageData,f as default};
